import React, { useState } from 'react';
import axios from 'axios';
import MapDisplay from './components/MapDisplay';
import SafetyIndicators from './components/SafetyIndicators';
import SOSButton from './components/SOSButton';
import './App.css';
// Add heroicons for better visuals (run: npm install @heroicons/react)
import { MapPinIcon, MagnifyingGlassIcon } from '@heroicons/react/24/solid';

function App() {
  const [source, setSource] = useState('');
  const [destination, setDestination] = useState('');
  const [sourceCoords, setSourceCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [routeFound, setRouteFound] = useState(false);
  const [loading, setLoading] = useState(false);

  const geocode = async (place) => {
    // ... keep your existing geocode logic ...
    const res = await axios.get(`https://nominatim.openstreetmap.org/search`, {
      params: { q: place, format: 'json', limit: 1 },
    });
    if (res.data.length > 0) {
      return { lat: parseFloat(res.data[0].lat), lng: parseFloat(res.data[0].lon) };
    }
    return null;
  };

  const handleFindRoute = async () => {
    if (!source.trim() || !destination.trim()) return alert('Please enter both locations');
    setLoading(true);
    const src = await geocode(source);
    const dest = await geocode(destination);
    setLoading(false);

    if (!src || !dest) return alert('Could not find coordinates');

    setSourceCoords(src);
    setDestinationCoords(dest);
    setRouteFound(true);
  };

  return (
    <div className="relative h-screen w-full bg-gray-100 font-sans">
      {/* Background Map - Now Full Screen */}
      <div className="absolute inset-0 z-0">
         <MapDisplay source={sourceCoords} destination={destinationCoords} />
      </div>

      {/* Floating UI Card */}
      <div className="absolute top-6 left-6 z-10 w-full max-w-md">
        <div className="bg-white/90 backdrop-blur-md shadow-2xl rounded-2xl p-6 border border-white/20">
          <h1 className="text-3xl font-extrabold bg-gradient-to-r from-purple-600 to-pink-500 bg-clip-text text-transparent mb-6">
            SheRoute
          </h1>
          
          <div className="space-y-4">
            {/* Source Input */}
            <div className="relative">
              <MapPinIcon className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
              <input
                type="text"
                placeholder="Current Location"
                value={source}
                onChange={(e) => setSource(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all"
              />
            </div>

            {/* Destination Input */}
            <div className="relative">
              <MapPinIcon className="absolute left-3 top-3 h-5 w-5 text-purple-500" />
              <input
                type="text"
                placeholder="Where to?"
                value={destination}
                onChange={(e) => setDestination(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all"
              />
            </div>

            {/* Action Button */}
            <button
              onClick={handleFindRoute}
              disabled={loading}
              className="w-full flex items-center justify-center space-x-2 bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700 text-white font-bold py-3 px-4 rounded-xl shadow-lg transform transition-transform active:scale-95"
            >
              <MagnifyingGlassIcon className="h-5 w-5" />
              <span>{loading ? 'Routing...' : 'Find Safe Route'}</span>
            </button>
          </div>

          {routeFound && (
            <div className="mt-6 pt-6 border-t border-gray-200">
               <SafetyIndicators />
            </div>
          )}
        </div>
      </div>

      {/* Floating SOS Button */}
      <SOSButton />
    </div>
  );
}

export default App;
